def clean_path_text(raw: object) -> str:
    text = str(raw or "").strip()
    if len(text) >= 2 and text[0] == text[-1] and text[0] in {"'", '"'}:
        text = text[1:-1].strip()
    return text


def safe_resolve_path(path: Path) -> Path:
    try:
        return path.expanduser().resolve()
    except Exception:
        return path.expanduser().absolute()


def resolve_gmod_path_input(raw: object) -> dict[str, object]:
    text = clean_path_text(raw)
    if not text:
        return {"ok": False, "input": "", "error": "No GMod or StudioMDL path was entered."}
    path = safe_resolve_path(Path(text))
    if path.name.lower() == "studiomdl.exe":
        if path.exists():
            return {
                "ok": True,
                "input": text,
                "display": str(path),
                "kind": "studiomdl",
                "gmod_root": "",
                "studiomdl": str(path),
            }
        return {"ok": False, "input": text, "error": f"studiomdl.exe was not found: {path}"}
    if path.is_dir():
        install_studiomdl = path / "bin" / "studiomdl.exe"
        if install_studiomdl.exists():
            return {
                "ok": True,
                "input": text,
                "display": str(path),
                "kind": "install_root",
                "gmod_root": str(path),
                "studiomdl": "",
            }
        local_studiomdl = path / "studiomdl.exe"
        if local_studiomdl.exists():
            return {
                "ok": True,
                "input": text,
                "display": str(local_studiomdl),
                "kind": "studiomdl",
                "gmod_root": "",
                "studiomdl": str(local_studiomdl),
            }
        if path.name.lower() == "garrysmod":
            sibling_studiomdl = path.parent / "bin" / "studiomdl.exe"
            if sibling_studiomdl.exists():
                return {
                    "ok": True,
                    "input": text,
                    "display": str(path),
                    "kind": "game_dir",
                    "gmod_root": str(path),
                    "studiomdl": "",
                }
        return {"ok": False, "input": text, "error": f"GMod install does not contain studiomdl.exe: {path}"}
    return {"ok": False, "input": text, "error": f"GMod/StudioMDL path was not found: {path}"}


def split_gmod_path_input(raw: object) -> tuple[str, str]:
    resolved = resolve_gmod_path_input(raw)
    if resolved.get("ok"):
        return str(resolved.get("gmod_root") or ""), str(resolved.get("studiomdl") or "")
    text = clean_path_text(raw)
    if not text:
        return "", ""
    path = Path(text)
    if path.name.lower() == "studiomdl.exe":
        return "", text
    return text, ""


def gmod_game_dir_from_path_input(raw: object) -> tuple[Path | None, str]:
    resolved = resolve_gmod_path_input(raw)
    if not resolved.get("ok"):
        return None, str(resolved.get("error") or "Garry's Mod path is not valid.")
    kind = str(resolved.get("kind") or "")
    if kind == "studiomdl":
        studiomdl = safe_resolve_path(Path(str(resolved.get("studiomdl") or "")))
        game_dir = studiomdl.parent.parent / "garrysmod"
    elif kind == "install_root":
        game_dir = safe_resolve_path(Path(str(resolved.get("gmod_root") or ""))) / "garrysmod"
    elif kind == "game_dir":
        game_dir = safe_resolve_path(Path(str(resolved.get("gmod_root") or "")))
    else:
        return None, "Garry's Mod path type is not recognized."
    if not game_dir.exists():
        return None, f"Garry's Mod game folder was not found: {game_dir}"
    if not (game_dir / "gameinfo.txt").exists():
        return None, f"Selected path does not look like a Garry's Mod game folder: {game_dir}"
    addons_dir = game_dir / "addons"
    if not addons_dir.exists():
        return None, f"Garry's Mod addons folder was not found: {addons_dir}"
    return game_dir, ""


def is_dynamic_model_importer_manifest(payload: object) -> bool:
    if not isinstance(payload, dict):
        return False
    kind = str(payload.get("kind") or "").strip().lower()
    if kind == "dynamic_model_importer_manifest":
        return True
    generated_by = str(payload.get("generated_by") or "").strip().lower()
    if "mmd character importer" in generated_by:
        return True
    paths = payload.get("paths")
    return isinstance(paths, dict) and bool(payload.get("manifest_id")) and bool(paths.get("model"))


def load_dynamic_model_importer_manifest(path: Path) -> dict[str, object] | None:
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None
    if not is_dynamic_model_importer_manifest(payload):
        return None
    return payload


def addon_dir_has_importer_manifest(addon_dir: Path) -> bool:
    manifest_dir = addon_dir / "data_static" / "dynamic_model_importer" / "models"
    if not manifest_dir.exists():
        return False
    for manifest_path in manifest_dir.glob("*.json"):
        if load_dynamic_model_importer_manifest(manifest_path) is not None:
            return True
    return False


def folder_size_and_mtime(root: Path) -> tuple[int, float]:
    total_size = 0
    newest_mtime = 0.0
    stack = [Path(root)]
    while stack:
        folder = stack.pop()
        try:
            stat = folder.stat()
            newest_mtime = max(newest_mtime, float(stat.st_mtime))
        except OSError:
            pass
        try:
            with os.scandir(folder) as entries:
                for entry in entries:
                    try:
                        if entry.is_dir(follow_symlinks=False):
                            stack.append(Path(entry.path))
                        else:
                            stat = entry.stat(follow_symlinks=False)
                            total_size += int(stat.st_size)
                            newest_mtime = max(newest_mtime, float(stat.st_mtime))
                    except OSError:
                        continue
        except OSError:
            continue
    return total_size, newest_mtime


def scan_importer_model_addons(gmod_path: object) -> dict[str, object]:
    game_dir, error = gmod_game_dir_from_path_input(gmod_path)
    if game_dir is None:
        raise RuntimeError(error)
    addons_dir = game_dir / "addons"
    models: list[dict[str, object]] = []
    with os.scandir(addons_dir) as entries:
        addon_dirs = sorted(
            (Path(entry.path) for entry in entries if entry.is_dir(follow_symlinks=False)),
            key=lambda item: item.name.lower(),
        )
    for addon_dir in addon_dirs:
        manifest_dir = addon_dir / "data_static" / "dynamic_model_importer" / "models"
        if not manifest_dir.exists():
            continue
        manifests: list[dict[str, object]] = []
        manifest_paths: list[str] = []
        for manifest_path in sorted(manifest_dir.glob("*.json"), key=lambda item: item.name.lower()):
            payload = load_dynamic_model_importer_manifest(manifest_path)
            if payload is None:
                continue
            manifests.append(payload)
            manifest_paths.append(str(manifest_path))
        if not manifests:
            continue
        display_names: list[str] = []
        manifest_ids: list[str] = []
        authors: list[str] = []
        categories: list[str] = []
        model_paths: list[str] = []
        for manifest in manifests:
            display = str(manifest.get("display_name") or manifest.get("model_name") or manifest.get("manifest_id") or "").strip()
            if display and display not in display_names:
                display_names.append(display)
            manifest_id = str(manifest.get("manifest_id") or manifest.get("addon_id") or "").strip()
            if manifest_id and manifest_id not in manifest_ids:
                manifest_ids.append(manifest_id)
            author = str(manifest.get("author") or "").strip()
            if author and author not in authors:
                authors.append(author)
            category = str(manifest.get("category_readable") or manifest.get("character_category") or "").strip()
            if category and category not in categories:
                categories.append(category)
            paths = manifest.get("paths")
            if isinstance(paths, dict):
                for key in ("model", "player_model", "arms_model"):
                    model_path = str(paths.get(key) or "").strip()
                    if model_path and model_path not in model_paths:
                        model_paths.append(model_path)
        size_bytes, modified_time = folder_size_and_mtime(addon_dir)
        models.append(
            {
                "addon_dir": str(addon_dir),
                "addon_name": addon_dir.name,
                "display_names": display_names,
                "manifest_ids": manifest_ids,
                "authors": authors,
                "categories": categories,
                "model_paths": model_paths,
                "manifest_count": len(manifests),
                "manifest_paths": manifest_paths,
                "size_bytes": size_bytes,
                "modified_time": modified_time,
            }
        )
    return {"game_dir": str(game_dir), "addons_dir": str(addons_dir), "models": models}


def sanitize_internal_identifier_text(value: object) -> str:
    return INTERNAL_IDENTIFIER_UNSAFE_RE.sub("", str(value or ""))


def sanitize_display_name_text(value: object) -> str:
    return DISPLAY_NAME_UNSAFE_RE.sub("", str(value or ""))


def sanitize_category_display_name_text(value: object) -> str:
    return CATEGORY_DISPLAY_UNSAFE_RE.sub("", str(value or ""))


def parse_utc_datetime(value: object) -> datetime | None:
    text = str(value or "").strip()
    if not text:
        return None
    if text.endswith("Z"):
        text = text[:-1] + "+00:00"
    try:
        parsed = datetime.fromisoformat(text)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def load_build_info() -> dict[str, object]:
    candidates = [ROOT_DIR / "build_info.json"]
    if getattr(sys, "frozen", False):
        exe_dir = Path(sys.executable).resolve().parent
        candidates.extend(
            [
                exe_dir / "build_info.json",
                exe_dir / "GmodSimpleMMDCharacterImporter_build_info.json",
                exe_dir / "GmodSimpleMMDCharacterImporter_dependency_manifest.json",
                exe_dir / "MMDCharacterImporter_build_info.json",
                exe_dir / "MMDCharacterImporter_dependency_manifest.json",
                exe_dir / "dependency_manifest.json",
            ]
        )
    for candidate in candidates:
        try:
            if not candidate.exists():
                continue
            data = json.loads(candidate.read_text(encoding="utf-8"))
        except Exception:
            continue
        if isinstance(data, dict) and data.get("build_time_utc"):
            data = dict(data)
            data["build_info_path"] = str(candidate)
            return data
    return {}


def is_valid_display_name_text(value: object, allow_blank: bool = True) -> bool:
    text = str(value or "")
    if allow_blank and not text.strip():
        return True
    return bool(DISPLAY_NAME_ALLOWED_RE.fullmatch(text))


def is_valid_category_display_name_text(value: object, allow_blank: bool = True) -> bool:
    text = str(value or "")
    if allow_blank and not text.strip():
        return True
    return bool(CATEGORY_DISPLAY_ALLOWED_RE.fullmatch(text))


def category_suggestion_file_paths() -> list[Path]:
    paths: list[Path] = [CATEGORY_SUGGESTIONS_FILE]
    if LOCAL_CATEGORY_SUGGESTIONS_FILE not in paths:
        paths.append(LOCAL_CATEGORY_SUGGESTIONS_FILE)
    for raw in str(os.environ.get(CATEGORY_SUGGESTIONS_ENV) or "").split(os.pathsep):
        text = raw.strip()
        if not text:
            continue
        path = Path(text)
        if path not in paths:
            paths.append(path)
    return paths


def category_config_entries(raw_categories: object) -> Iterable[tuple[str, str]]:
    if isinstance(raw_categories, dict):
        for internal, display in raw_categories.items():
            yield str(internal or "").strip(), sanitize_category_display_name_text(display).strip()
        return
    if not isinstance(raw_categories, list):
        return
    for item in raw_categories:
        if isinstance(item, dict):
            internal = str(item.get("internal") or item.get("id") or item.get("name") or "").strip()
            display = sanitize_category_display_name_text(item.get("display") or item.get("label") or "").strip()
            yield internal, display


def load_category_suggestion_config() -> tuple[dict[str, str], list[Path], list[Path]]:
    categories: dict[str, str] = {}
    scan_roots: list[Path] = []
    loaded_files: list[Path] = []
    for path in category_suggestion_file_paths():
        if not path.exists() or not path.is_file():
            continue
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(data, dict):
            continue
        loaded_files.append(path)
        raw_scan_roots = data.get("scan_roots", [])
        if isinstance(raw_scan_roots, str):
            raw_scan_roots = [raw_scan_roots]
        if isinstance(raw_scan_roots, list):
            for raw in raw_scan_roots:
                text = str(raw or "").strip()
                if text:
                    scan_roots.append(Path(text))
        for internal, display in category_config_entries(data.get("categories", {})):
            if re.fullmatch(r"[A-Za-z_]+", internal or "") and display:
                categories[internal] = display
    for internal, display in DEFAULT_CATEGORY_SUGGESTIONS.items():
        categories.setdefault(internal, display)
    env_scan_root = str(os.environ.get(CATEGORY_SCAN_ROOT_ENV) or "").strip()
    if env_scan_root:
        scan_roots.insert(0, Path(env_scan_root))
    if not scan_roots:
        scan_roots.extend(DEFAULT_CATEGORY_SCAN_ROOTS)
    deduped_scan_roots: list[Path] = []
    seen_roots: set[str] = set()
    for root in scan_roots:
        key = str(root).casefold()
        if key in seen_roots:
            continue
        seen_roots.add(key)
        deduped_scan_roots.append(root)
    return categories, deduped_scan_roots, loaded_files


