                Path(self.input_path),
                custom_source_image=custom,
                icon_basename=self.icon_basename,
                body_vmd_path=Path(self.body_vmd) if self.body_vmd else None,
                face_vmd_paths=[Path(path) for path in self.face_vmds if path],
