    def on_main_source_changed(self, _value: str) -> None:
        self.current_main_analysis = None
        self.current_main_workspace = None
        self.main_workspace_edit.clear()
        self.main_stats_label.setText("Refresh PMX files, then run preflight.")
        self.main_warning_label.clear()
        self.main_open_output_button.setEnabled(False)
        if self.main_model_preview is not None:
            self.main_model_preview.clear_model()
        self.populate_main_pmx_files()
        self.save_settings()

    def populate_main_pmx_files(self) -> None:
        source = Path(self.main_source_row.value()) if self.main_source_row.value() else None
        previous = str(self.settings_store.value("main_pmx_path", "", str) or "")
        self.main_pmx_paths = []
        self.main_pmx_combo.blockSignals(True)
        self.main_pmx_combo.clear()
        if source and source.exists():
            self.main_pmx_paths = core.find_pmx_files(source)
            for path in self.main_pmx_paths:
                try:
                    label = str(path.relative_to(source))
                except ValueError:
                    label = path.name
                self.main_pmx_combo.addItem(label, str(path))
            if previous:
                index = self.main_pmx_combo.findData(previous)
                if index >= 0:
                    self.main_pmx_combo.setCurrentIndex(index)
        self.main_pmx_combo.blockSignals(False)
        if self.main_pmx_paths:
            self.analyze_main_pmx(silent=True)
        else:
            self.main_stats_label.setText("No .pmx files found in the selected folder.")
            self.main_warning_label.clear()

    def on_main_pmx_changed(self, _index: int) -> None:
        self.current_main_analysis = None
        self.current_main_workspace = None
        self.main_workspace_edit.clear()
        self.main_warning_label.clear()
        if self.main_model_preview is not None:
            self.main_model_preview.clear_model()
        if self.current_main_pmx_path():
            self.analyze_main_pmx(silent=True)
        self.save_settings()

    def current_main_pmx_path(self) -> Path | None:
        raw = self.main_pmx_combo.currentData()
        return Path(str(raw)) if raw else None

    def analyze_main_pmx(self, silent: bool = False) -> core.PmxAnalysis | None:
        pmx = self.current_main_pmx_path()
        source_raw = self.main_source_row.value()
        if not pmx or not source_raw:
            if not silent:
                self.show_error("Preflight failed", "Select a model folder and PMX file first.")
            return None
        try:
            source = Path(source_raw)
            analysis = core.analyze_pmx(pmx, source)
            custom_root = Path(self.main_workspace_edit.text().strip()) if self.main_workspace_edit.text().strip() else None
            workspace = core.build_workspace(pmx, source, analysis, workspace_root=custom_root)
            self.current_main_analysis = analysis
            self.current_main_workspace = workspace
            self.main_workspace_edit.setText(str(workspace.root))
            self.render_main_analysis(analysis)
            self.load_main_preview(silent=True)
            if not self.main_model_name_edit.text().strip():
                candidate = core.slugify(analysis.model_name or pmx.stem)
                candidate = re.sub(r"[^A-Za-z_]+", "_", candidate).strip("_")
                if candidate:
                    self.main_model_name_edit.setPlaceholderText(f"Optional, default: {candidate}")
                    self.update_main_display_placeholders(default_model=candidate)
            if not silent:
                self.append_main_log(f"Analyzed PMX: {pmx}")
            self.save_settings()
            return analysis
        except Exception as exc:
            self.current_main_analysis = None
            self.current_main_workspace = None
            self.main_workspace_edit.clear()
            self.main_stats_label.setText("Could not analyze the selected PMX.")
            self.main_warning_label.setText(f'<span style="color:#f85149;">{html.escape(str(exc))}</span>')
            if self.main_model_preview is not None:
                self.main_model_preview.clear_model()
            if not silent:
                self.show_error("Preflight failed", str(exc))
            return None

    def render_main_analysis(self, analysis: core.PmxAnalysis) -> None:
        self.main_stats_label.setText(
            f"Model: {analysis.model_name or Path(analysis.pmx_path).stem}"
            f" | Vertices: {analysis.vertex_count:,}"
            f" | Morphs: {analysis.morph_count:,}"
            f" | PMX textures: {analysis.texture_ref_count:,}"
            f" | Resolved textures: {analysis.resolved_texture_count:,}/{analysis.texture_ref_count:,}"
            f" | Bones: {analysis.bone_count:,}"
            f" | Materials: {analysis.material_count:,}"
        )
        if analysis.warnings:
            escaped = "<br>".join(html.escape(f"- {self.translate_preflight_warning(warning)}") for warning in analysis.warnings)
            self.main_warning_label.setText(f'<span style="color:#d29922;">{html.escape(self._t("preflight.warning_label", "Warnings:"))}</span><br>{escaped}')
        else:
            self.main_warning_label.setText(
                f'<span style="color:#2ea043;">{html.escape(self._t("preflight.no_warnings", "No preflight warnings."))}</span>'
            )

    def load_main_preview(self, silent: bool = False) -> None:
        if self.main_model_preview is None:
            return
        pmx = self.current_main_pmx_path()
        if not pmx:
            self.main_model_preview.clear_model()
            return
        try:
            model = self.main_model_preview.load_model(pmx)
            self.main_preview_status_label.setText(
                f"OpenGL preview loaded | {model.vertex_count:,} verts | {model.triangle_count:,} tris | "
                f"{len(model.bones):,} bones | {model.morph_count:,} morphs | {len(model.materials):,} materials"
            )
            if not silent:
                self.append_main_log(f"Loaded PMX preview: {pmx}")
        except Exception as exc:
            self.main_model_preview.clear_model()
            self.main_preview_status_label.setText(f"Preview failed: {exc}")
            if not silent:
                self.show_error("Preview failed", str(exc))

    def find_gmod_candidate(self) -> str:
        candidates: list[Path] = []
        # 1. Environment variables (highest priority when explicitly set)
        for key in ("STUDIOMDL", "GMOD_PATH"):
            raw = os.environ.get(key, "")
            if raw:
                path = Path(raw)
                candidates.append(path)
                if path.is_dir():
                    candidates.append(path / "bin" / "studiomdl.exe")
        # 2. Detect Steam installation and libraries first
        steam_dir = core._find_steam_dir()
        if steam_dir:
            for lib in core._find_steam_library_folders(steam_dir):
                for name in ("GarrysMod_RTX_c", "GarrysMod"):
                    candidates.append(lib / "steamapps" / "common" / name / "bin" / "studiomdl.exe")
        # 3. Fallback hardcoded paths
        for root in (
            Path("H:/SteamLibrary/steamapps/common/GarrysMod_RTX_c"),
            Path("H:/SteamLibrary/steamapps/common/GarrysMod"),
            Path("C:/Program Files (x86)/Steam/steamapps/common/GarrysMod"),
        ):
            candidates.append(root / "bin" / "studiomdl.exe")
        seen: set[Path] = set()
        for candidate in candidates:
            candidate = safe_resolve_path(candidate)
            if candidate in seen:
                continue
            seen.add(candidate)
            resolved = resolve_gmod_path_input(str(candidate))
            if resolved.get("ok"):
                return str(resolved.get("display") or candidate)
        return ""

    def detect_gmod_for_main(self) -> None:
        current = resolve_gmod_path_input(self.main_gmod_row.value() if hasattr(self, "main_gmod_row") else "")
        if current.get("ok"):
            found = str(current.get("display") or "")
            self.main_gmod_row.set_value(found)
            self.append_main_log(f"Using existing GMod StudioMDL/install path: {found}")
            self.save_settings()
            return
        found = self.find_gmod_candidate()
        if found:
            self.main_gmod_row.set_value(found)
            self.append_main_log(f"Detected GMod StudioMDL/install: {found}")
            self.save_settings()
            return
        detail = str(current.get("error") or "").strip()
        if detail and self.main_gmod_row.value().strip():
            detail = "\n\nCurrent path is not usable:\n" + detail
        self.show_error(
            "Detect GMod",
            "Could not find Garry's Mod StudioMDL. Browse to garrysmod/bin/studiomdl.exe or set STUDIOMDL." + detail,
        )

    def browse_model_manager_gmod_folder(self) -> None:
        current = self.model_manager_gmod_row.value() if hasattr(self, "model_manager_gmod_row") else ""
        start = str(Path.home())
        game_dir, _error = gmod_game_dir_from_path_input(current)
        if game_dir is not None:
            start = str(game_dir.parent)
        elif current:
            current_path = Path(current)
            start = str(current_path.parent if current_path.is_file() else current_path)
        selected = QtWidgets.QFileDialog.getExistingDirectory(self, "Select Garry's Mod folder", start)
        if selected:
            self.model_manager_gmod_row.set_value(selected)
            self.save_settings()

    def detect_gmod_for_model_manager(self) -> None:
        candidates: list[str] = []
        for attr in ("model_manager_gmod_row", "main_gmod_row", "qc_gmod_row"):
            row = getattr(self, attr, None)
            if row is not None and hasattr(row, "value"):
                value = str(row.value()).strip()
                if value and value not in candidates:
                    candidates.append(value)
        for candidate in candidates:
            resolved = resolve_gmod_path_input(candidate)
            if resolved.get("ok"):
                found = str(resolved.get("display") or candidate)
                self.model_manager_gmod_row.set_value(found)
                self.model_manager_summary_label.setText(f"Using GMod path: {found}")
                self.save_settings()
                self.refresh_model_manager_models()
                return
        found = self.find_gmod_candidate()
        if found:
            self.model_manager_gmod_row.set_value(found)
            self.model_manager_summary_label.setText(f"Detected GMod path: {found}")
            self.save_settings()
            self.refresh_model_manager_models()
            return
        self.show_error(
            "Detect GMod",
            "Could not find Garry's Mod StudioMDL. Browse to garrysmod/bin/studiomdl.exe or the Garry's Mod install folder.",
        )

    def open_model_manager_addons_folder(self) -> None:
        addons_dir = Path(self.model_manager_addons_dir) if self.model_manager_addons_dir else None
        if addons_dir is None or not addons_dir.exists():
            game_dir, error = gmod_game_dir_from_path_input(self.model_manager_gmod_row.value())
            if game_dir is None:
                self.show_error("Open Addons Folder", error)
                return
            addons_dir = game_dir / "addons"
        if not QtGui.QDesktopServices.openUrl(QtCore.QUrl.fromLocalFile(str(addons_dir))):
            self.statusBar().showMessage(str(addons_dir))

    def refresh_model_manager_models(self) -> None:
        worker = self.model_manager_scan_worker
        if worker is not None and worker.isRunning():
            return
        path = self.model_manager_gmod_row.value() if hasattr(self, "model_manager_gmod_row") else ""
        if not path.strip():
            fallback = self.main_gmod_row.value() if hasattr(self, "main_gmod_row") else ""
            if fallback.strip():
                self.model_manager_gmod_row.set_value(fallback)
                path = fallback
        if not path.strip():
            self.show_error("Scan Ported Models", "Select or detect a Garry's Mod path first.")
            return
        self.model_manager_summary_label.setText("Scanning Garry's Mod addons for importer manifests...")
        self.model_manager_scan_button.setEnabled(False)
        self.model_manager_remove_button.setEnabled(False)
        worker = ModelManagerScanWorker(path)
        self.model_manager_scan_worker = worker
        worker.done.connect(self.on_model_manager_scan_done)
        worker.failed.connect(self.on_model_manager_scan_failed)
        worker.finished.connect(self.on_model_manager_scan_finished)
        worker.start()

    def on_model_manager_scan_done(self, result: dict) -> None:
        self.model_manager_models = list(result.get("models") or [])
        self.model_manager_addons_dir = str(result.get("addons_dir") or "")
        self.populate_model_manager_table()
        total_size = sum(int(model.get("size_bytes") or 0) for model in self.model_manager_models)
        count = len(self.model_manager_models)
        if count:
            self.model_manager_summary_label.setText(
                f"Found {count} tagged addon folder(s). Total size: {self.format_file_size(total_size)}. Addons folder: {self.model_manager_addons_dir}"
            )
        else:
            self.model_manager_summary_label.setText(f"No tagged importer addon folders found in: {self.model_manager_addons_dir}")

    def on_model_manager_scan_failed(self, message: str) -> None:
        self.model_manager_models = []
        self.model_manager_addons_dir = ""
        self.populate_model_manager_table()
        self.model_manager_summary_label.setText("Scan failed.")
        self.show_error("Scan Ported Models", message)

    def on_model_manager_scan_finished(self) -> None:
        self.model_manager_scan_worker = None
        self.update_model_manager_buttons()

    def model_manager_item(self, text: object, model: dict[str, object] | None = None) -> QtWidgets.QTableWidgetItem:
        item = QtWidgets.QTableWidgetItem(str(text or ""))
        if model is not None:
            item.setData(QtCore.Qt.ItemDataRole.UserRole, model)
        return item

    def populate_model_manager_table(self) -> None:
        table = self.model_manager_table
        table.setSortingEnabled(False)
        table.setRowCount(0)
        for model in self.model_manager_models:
            row = table.rowCount()
            table.insertRow(row)
            display_names = model.get("display_names") if isinstance(model.get("display_names"), list) else []
            manifest_ids = model.get("manifest_ids") if isinstance(model.get("manifest_ids"), list) else []
            authors = model.get("authors") if isinstance(model.get("authors"), list) else []
            categories = model.get("categories") if isinstance(model.get("categories"), list) else []
            model_paths = model.get("model_paths") if isinstance(model.get("model_paths"), list) else []
            name = ", ".join(str(item) for item in display_names) or ", ".join(str(item) for item in manifest_ids) or str(model.get("addon_name") or "")
            modified_time = float(model.get("modified_time") or 0.0)
            modified_text = datetime.fromtimestamp(modified_time).strftime("%Y-%m-%d %H:%M") if modified_time > 0 else ""
            size_bytes = int(model.get("size_bytes") or 0)

            class _NumericRoleItem(QtWidgets.QTableWidgetItem):
                def __lt__(self, other):  # type: ignore[override]
                    try:
                        return int(self.data(QtCore.Qt.ItemDataRole.UserRole + 1) or 0) < int(
                            other.data(QtCore.Qt.ItemDataRole.UserRole + 1) or 0
                        )
                    except Exception:
                        return super().__lt__(other)

            cells = [
                name,
                str(model.get("addon_name") or Path(str(model.get("addon_dir") or "")).name),
                self.format_file_size(size_bytes),
                modified_text,
                ", ".join(str(item) for item in authors),
                ", ".join(str(item) for item in categories),
                "\n".join(str(item) for item in model_paths),
            ]
            for column, cell in enumerate(cells):
                if column == 2:
                    item = _NumericRoleItem(str(cell))
                    item.setData(QtCore.Qt.ItemDataRole.UserRole + 1, size_bytes)
                else:
                    item = self.model_manager_item(cell, model if column == 0 else None)
                item.setToolTip(str(cell))
                table.setItem(row, column, item)
        table.resizeColumnsToContents()
        table.setSortingEnabled(True)
        self.update_model_manager_buttons()

    def selected_model_manager_models(self) -> list[dict[str, object]]:
        table = getattr(self, "model_manager_table", None)
        if not isinstance(table, QtWidgets.QTableWidget):
            return []
        selection = table.selectionModel()
        if selection is None:
            return []
        models: list[dict[str, object]] = []
        seen: set[str] = set()
        for index in selection.selectedRows():
            item = table.item(index.row(), 0)
            if item is None:
                continue
            model = item.data(QtCore.Qt.ItemDataRole.UserRole)
            if not isinstance(model, dict):
                continue
            addon_dir = str(model.get("addon_dir") or "")
            if addon_dir and addon_dir not in seen:
                seen.add(addon_dir)
                models.append(model)
        return models

    def update_model_manager_buttons(self) -> None:
        scanning = bool(self.model_manager_scan_worker and self.model_manager_scan_worker.isRunning())
        removing = bool(self.model_manager_remove_worker and self.model_manager_remove_worker.isRunning())
        busy = scanning or removing
        selected = bool(self.selected_model_manager_models())
        for attr in ("model_manager_detect_button", "model_manager_browse_folder_button", "model_manager_scan_button", "model_manager_open_addons_button"):
            button = getattr(self, attr, None)
            if isinstance(button, QtWidgets.QPushButton):
                button.setEnabled(not busy)
        button = getattr(self, "model_manager_remove_button", None)
        if isinstance(button, QtWidgets.QPushButton):
            button.setEnabled(not busy and selected)

    def remove_selected_model_manager_models(self) -> None:
        selected = self.selected_model_manager_models()
        if not selected:
            self.statusBar().showMessage("No ported model addon folder selected.")
            return
        if not self.model_manager_addons_dir:
            game_dir, error = gmod_game_dir_from_path_input(self.model_manager_gmod_row.value())
            if game_dir is None:
                self.show_error("Remove Selected", error)
                return
            self.model_manager_addons_dir = str(game_dir / "addons")
        names = []
        for model in selected:
            display_names = model.get("display_names") if isinstance(model.get("display_names"), list) else []
            name = ", ".join(str(item) for item in display_names) or str(model.get("addon_name") or model.get("addon_dir") or "")
            names.append(f"- {name} ({self.format_file_size(int(model.get('size_bytes') or 0))})")
        message = (
            "Remove the selected generated addon folder(s)?\n\n"
            + "\n".join(names[:12])
            + ("\n..." if len(names) > 12 else "")
            + "\n\nThis deletes the whole addon folder from Garry's Mod addons. It cannot be undone from this tool."
        )
        reply = QtWidgets.QMessageBox.warning(
            self,
            "Remove Ported Models",
            message,
            QtWidgets.QMessageBox.StandardButton.Yes | QtWidgets.QMessageBox.StandardButton.No,
            QtWidgets.QMessageBox.StandardButton.No,
        )
        if reply != QtWidgets.QMessageBox.StandardButton.Yes:
            return
        addon_dirs = [str(model.get("addon_dir") or "") for model in selected if str(model.get("addon_dir") or "")]
        if not addon_dirs:
            return
        self.model_manager_summary_label.setText("Removing selected generated addon folder(s)...")
        worker = ModelManagerRemoveWorker(self.model_manager_addons_dir, addon_dirs)
        self.model_manager_remove_worker = worker
        worker.done.connect(self.on_model_manager_remove_done)
        worker.failed.connect(self.on_model_manager_remove_failed)
        worker.finished.connect(self.on_model_manager_remove_finished)
        self.update_model_manager_buttons()
        worker.start()

    def on_model_manager_remove_done(self, result: dict) -> None:
        removed = list(result.get("removed") or [])
        failures = list(result.get("failures") or [])
        if failures:
            self.show_error(
                "Remove Ported Models",
                f"Removed {len(removed)} addon folder(s), but some items failed:\n\n" + "\n".join(str(item) for item in failures),
            )
        else:
            QtWidgets.QMessageBox.information(self, "Remove Ported Models", f"Removed {len(removed)} addon folder(s).")
        self.refresh_model_manager_models()

    def on_model_manager_remove_failed(self, message: str) -> None:
        self.model_manager_summary_label.setText("Remove failed.")
        self.show_error("Remove Ported Models", message)

    def on_model_manager_remove_finished(self) -> None:
        self.model_manager_remove_worker = None
        self.update_model_manager_buttons()

    def update_main_display_placeholders(self, default_model: str = "") -> None:
        if hasattr(self, "main_category_display_edit"):
            category = self.main_category_edit.text().strip() if hasattr(self, "main_category_edit") else "SheepyLord"
            known_display = self.known_category_display_for_internal(category)
            self.main_category_display_edit.setPlaceholderText(
                f"{self._t('main.auto_prefix', 'Auto')}: {known_display or self.qc_display_from_internal(category, 'Sheepy Lord')}"
            )
        if hasattr(self, "main_model_display_edit"):
            model = self.main_model_name_edit.text().strip() if hasattr(self, "main_model_name_edit") else ""
            if not model:
                model = default_model or self.main_effective_model_name()
            self.main_model_display_edit.setPlaceholderText(
                f"{self._t('main.auto_prefix', 'Auto')}: {self.qc_display_from_internal(model, 'Mmd Model')}"
            )

    def bodygroup_vertex_limit(self) -> int:
        enabled = False
        if hasattr(self, "bodygroup_rtx_limit_check"):
            enabled = enabled or bool(self.bodygroup_rtx_limit_check.isChecked())
        if hasattr(self, "main_rtx_bodygroup_limit_check"):
            enabled = enabled or bool(self.main_rtx_bodygroup_limit_check.isChecked())
        return int(getattr(core, "RTX_BODYGROUP_VERTEX_LIMIT", 32767) if enabled else getattr(core, "DEFAULT_BODYGROUP_VERTEX_LIMIT", 65535))

    def settings_bool(self, value: object, default: bool = False) -> bool:
        if value is None:
            return bool(default)
        if isinstance(value, str):
            text = value.strip().lower()
            if text in {"0", "false", "no", "off"}:
                return False
            if text in {"1", "true", "yes", "on"}:
                return True
        return bool(value)

    def main_clear_custom_normals_enabled(self) -> bool:
        widget = getattr(self, "main_clear_custom_normals_check", None)
        if isinstance(widget, QtWidgets.QCheckBox):
            return bool(widget.isChecked())
        return True

    def fix_clear_custom_normals_enabled(self) -> bool:
        widget = getattr(self, "fix_clear_custom_normals_check", None)
        if isinstance(widget, QtWidgets.QCheckBox):
            return bool(widget.isChecked())
        return False

    def clear_custom_normals_enabled(self) -> bool:
        return self.fix_clear_custom_normals_enabled()

    def on_clear_custom_normals_changed(self, checked: bool) -> None:
        self.save_settings()

    def set_bodygroup_scale_preset(self, preset: str) -> None:
        preset = str(preset or "factor").lower()
        if preset not in {"factor", "tall", "normal", "short"}:
            preset = "factor"
        self.bodygroup_scale_preset = preset
        buttons = getattr(self, "bodygroup_scale_preset_buttons", {})
        button_items = buttons.items() if isinstance(buttons, dict) else []
        for name, button in button_items:
            if isinstance(button, QtWidgets.QPushButton):
                blocker = QtCore.QSignalBlocker(button)
                try:
                    button.setChecked(name == preset)
                finally:
                    del blocker
        if hasattr(self, "bodygroup_scale_preset_label"):
            if preset == "factor":
                text = "Default factor mode: scales by 40.457 only while model height is below 10 Blender units."
            else:
                reference = getattr(core, "BODYGROUP_SCALE_PRESETS", {}).get(preset) if hasattr(core, "BODYGROUP_SCALE_PRESETS") else None
                target_top = getattr(core, "BODYGROUP_SCALE_PRESET_TOPS", {}).get(preset) if hasattr(core, "BODYGROUP_SCALE_PRESET_TOPS") else None
                text = f"Preset mode: match current face/head top to {preset.title()} size"
                if target_top:
                    text += f" (target top {target_top:.3f})"
                if reference and Path(reference).exists():
                    text += f"; source Face.smd: {reference}"
            self.bodygroup_scale_preset_label.setText(text)
        self.save_settings()

    def on_bodygroup_rtx_limit_changed(self, checked: bool) -> None:
        for attr in ("main_rtx_bodygroup_limit_check", "bodygroup_rtx_limit_check"):
            widget = getattr(self, attr, None)
            if isinstance(widget, QtWidgets.QCheckBox) and widget.isChecked() != bool(checked):
                blocker = QtCore.QSignalBlocker(widget)
                try:
                    widget.setChecked(bool(checked))
                finally:
                    del blocker
        self.save_settings()
        self.update_bodygroup_limit_hint()

    def update_bodygroup_limit_hint(self) -> None:
        limit = self.bodygroup_vertex_limit()
        if hasattr(self, "bodygroup_always_auto_split_check"):
            self.bodygroup_always_auto_split_check.setToolTip(
                f"Off: show material-split bodygroups and only run advanced splitting when a separated mesh exceeds {limit:,} vertices."
            )
        if hasattr(self, "bodygroup_rtx_limit_check"):
            self.bodygroup_rtx_limit_check.setToolTip(
                f"When enabled, Step 6 validates and auto-splits bodygroups to {getattr(core, 'RTX_BODYGROUP_VERTEX_LIMIT', 32767):,} vertices for RTX Remix GMod builds."
            )

    def validate_main_import_inputs(self) -> list[str]:
        errors: list[str] = []
        if not self.current_main_pmx_path():
            errors.append("Select a PMX model.")
        if not self.main_source_row.value():
            errors.append("Select the MMD model folder.")
        gmod = self.main_gmod_row.value().strip()
        if not gmod:
            errors.append("Detect or browse to the GMod install/studiomdl.exe.")
        else:
            resolved_gmod = resolve_gmod_path_input(gmod)
            if not resolved_gmod.get("ok"):
                errors.append(str(resolved_gmod.get("error") or "Invalid GMod install/studiomdl.exe path."))
        category = self.main_effective_category()
        model = self.main_effective_model_name()
        if category and not INTERNAL_IDENTIFIER_REQUIRED_RE.fullmatch(category):
            errors.append("Category internal name must contain only English letters and underscores.")
        if model and not INTERNAL_IDENTIFIER_REQUIRED_RE.fullmatch(model):
            errors.append("Character internal name must contain only English letters and underscores.")
        category_display = (
            self.main_category_display_edit.text().strip()
            if hasattr(self, "main_category_display_edit") and self.main_category_display_edit.text().strip()
            else self.main_effective_category_display_name()
        )
        model_display = (
            self.main_model_display_edit.text().strip()
            if hasattr(self, "main_model_display_edit") and self.main_model_display_edit.text().strip()
            else self.main_effective_model_display_name()
        )
        if not is_valid_category_display_name_text(category_display, allow_blank=False):
            errors.append("Category display name must contain only printable ASCII characters.")
        if not is_valid_display_name_text(model_display, allow_blank=False):
            errors.append("Character display name must contain only English letters, spaces, and underscores.")
        return errors

    def main_effective_category(self) -> str:
        return self.main_category_edit.text().strip() or "SheepyLord"

    def main_effective_model_name(self) -> str:
        explicit = self.main_model_name_edit.text().strip()
        if explicit:
            return explicit
        analysis = self.current_main_analysis
        pmx = self.current_main_pmx_path()
        raw = analysis.model_name if analysis and analysis.model_name else (pmx.stem if pmx else "mmd_model")
        safe = re.sub(r"[^A-Za-z_]+", "_", core.slugify(raw)).strip("_")
        return safe or "mmd_model"

    def main_effective_category_display_name(self) -> str:
        explicit = self.main_category_display_edit.text().strip() if hasattr(self, "main_category_display_edit") else ""
        category = self.main_effective_category()
        return sanitize_category_display_name_text(
            explicit or self.known_category_display_for_internal(category) or self.qc_display_from_internal(category, "Sheepy Lord")
        )

    def main_effective_model_display_name(self) -> str:
        explicit = self.main_model_display_edit.text().strip() if hasattr(self, "main_model_display_edit") else ""
        return sanitize_display_name_text(explicit or self.qc_display_from_internal(self.main_effective_model_name(), "Mmd Model"))

    def start_full_import(self) -> None:
        if self.worker and self.worker.isRunning():
            return
        analysis = self.analyze_main_pmx(silent=False)
        if not analysis:
            return
        errors = self.validate_main_import_inputs()
        if errors:
            self.show_error("Import to GMod", "Blocking errors:\n" + "\n".join(f"- {error}" for error in errors))
            return
        if (analysis.warnings or self.analysis_has_content_warning(analysis)) and not self.confirm_main_warnings(analysis):
            return
        previous_output = str(self.settings_store.value("qc_gma_output_dir", "", str) or "")
        start_dir = previous_output if previous_output and Path(previous_output).exists() else str(Path.home() / "Desktop")
        selected_output = QtWidgets.QFileDialog.getExistingDirectory(
            self,
            "Select folder for the .gma and composed addon folder",
            start_dir,
        )
        if not selected_output:
            return
        self.settings_store.setValue("qc_gma_output_dir", selected_output)
        self.save_settings()
        self.main_log.clear()
        self.main_files_table.setRowCount(0)
        self.main_warnings_label.clear()
        self.set_main_progress(0, "Queued", "Preparing full import", "#58a6ff")
        self.main_import_button.setEnabled(False)
        self.main_preflight_button.setEnabled(False)
        self.main_detect_gmod_button.setEnabled(False)
        self.main_cancel_button.setEnabled(True)
        self.main_open_output_button.setEnabled(False)
        workspace_text = self.main_workspace_edit.text().strip()
        self.worker = FullImportWorker(
            str(self.current_main_pmx_path()),
            self.main_source_row.value(),
            self.main_gmod_row.value(),
            self.main_effective_category(),
            self.main_effective_category_display_name(),
            self.main_effective_model_name(),
            self.main_effective_model_display_name(),
            selected_output,
            self.bodygroup_vertex_limit(),
            self.main_clear_custom_normals_enabled(),
            workspace_text,
        )
        self.worker.log.connect(self.append_main_log)
        self.worker.progress.connect(self.set_main_progress)
        self.worker.done.connect(self.full_import_done)
        self.worker.failed.connect(self.full_import_failed)
        self.worker.start()

    def confirm_main_warnings(self, analysis: core.PmxAnalysis) -> bool:
        return self.confirm_preflight_warnings(
            analysis,
            self._t("preflight.title", "Preflight warnings"),
            self._t("preflight.generic_full_import", "The PMX has warnings. Proceed with the full import?"),
            full_import=True,
        )

    def analysis_has_content_warning(self, analysis: core.PmxAnalysis | None) -> bool:
        if analysis is None:
            return False
        scan = getattr(analysis, "content_warning_scan", None)
        return bool(isinstance(scan, dict) and scan.get("triggered"))

    def confirm_preflight_warnings(
        self,
        analysis: core.PmxAnalysis,
        title: str,
        generic_text: str,
        full_import: bool = False,
    ) -> bool:
        dialog = QtWidgets.QMessageBox(self)
        dialog.setIcon(QtWidgets.QMessageBox.Icon.Warning)
        scan = getattr(analysis, "content_warning_scan", {}) if analysis else {}
        content_triggered = isinstance(scan, dict) and bool(scan.get("triggered"))
        dialog.setWindowTitle(self._t("preflight.title_nsfw", "Potential NSFW model content") if content_triggered else title)
        if content_triggered:
            dialog.setText(
                self._t(
                    "preflight.nsfw_description",
                    "The program detected NSFW elements in the model you provided. "
                    "It is not encouraged to do so, and the automatic porting function is not optimized for that "
                    "and might return unexpected results.",
                )
            )
            match_count = int(scan.get("match_count") or 0)
            morph_count = int(scan.get("matched_morph_count") or 0)
            keywords = scan.get("matched_keywords") if isinstance(scan.get("matched_keywords"), list) else []
            keyword_preview = ", ".join(str(keyword) for keyword in keywords[:12])
            lines = [
                self._t(
                    "preflight.nsfw_detected",
                    "Detected {match_count} keyword match(es) across {morph_count} shapekey/morph name(s).",
                    match_count=f"{match_count:,}",
                    morph_count=f"{morph_count:,}",
                ),
                self._t(
                    "preflight.nsfw_continue_full",
                    "If you intend to continue, the manual step-by-step workflow is recommended over one-click auto porting.",
                )
                if full_import
                else self._t(
                    "preflight.nsfw_continue_manual",
                    "If you intend to continue, review each later step carefully and prefer manual corrections when needed.",
                ),
            ]
            if keyword_preview:
                suffix = "" if len(keywords) <= 12 else f" and {len(keywords) - 12} more"
                if suffix:
                    lines.append(
                        self._t(
                            "preflight.matched_keyword_hints_more",
                            "Matched keyword hints: {keywords} and {more_count} more",
                            keywords=keyword_preview,
                            more_count=len(keywords) - 12,
                        )
                    )
                else:
                    lines.append(
                        self._t(
                            "preflight.matched_keyword_hints",
                            "Matched keyword hints: {keywords}",
                            keywords=keyword_preview,
                        )
                    )
            other_warnings = [
                self.translate_preflight_warning(warning)
                for warning in analysis.warnings
                if "Potential NSFW shapekey names detected" not in warning
            ]
            if other_warnings:
                lines.append("")
                lines.append(self._t("preflight.other_warnings", "Other preflight warnings:"))
                lines.extend(f"- {warning}" for warning in other_warnings)
            dialog.setInformativeText("\n".join(lines))
        else:
            dialog.setText(generic_text)
            dialog.setInformativeText("\n".join(self.translate_preflight_warning(warning) for warning in analysis.warnings))
        proceed = dialog.addButton(
            self._t("preflight.proceed_anyway", "Proceed Anyway") if content_triggered else self._t("common.proceed", "Proceed"),
            QtWidgets.QMessageBox.ButtonRole.AcceptRole,
        )
        dialog.addButton(self._t("common.cancel", "Cancel"), QtWidgets.QMessageBox.ButtonRole.RejectRole)
        dialog.setDefaultButton(proceed)
        dialog.exec()
        return dialog.clickedButton() == proceed

    def translate_preflight_warning(self, warning: str) -> str:
        text = str(warning or "")
        if not text:
            return text
        match = re.fullmatch(r"Missing expected MMD humanoid skeleton groups: (.+)", text)
        if match:
            return self._t("preflight.warning_missing_skeleton_groups", "Missing expected MMD humanoid skeleton groups: {groups}", groups=match.group(1))
        if text == "No native texture files were found in the selected model folder.":
            return self._t("preflight.warning_no_native_textures", text)
        match = re.fullmatch(r"(\d+) PMX texture references could not be resolved: (.*) and (\d+) more", text)
        if match:
            return self._t(
                "preflight.warning_unresolved_texture_refs_more",
                "{count} PMX texture references could not be resolved: {refs} and {more_count} more",
                count=match.group(1),
                refs=match.group(2),
                more_count=match.group(3),
            )
        match = re.fullmatch(r"(\d+) PMX texture references could not be resolved: (.*)", text)
        if match:
            return self._t(
                "preflight.warning_unresolved_texture_refs",
                "{count} PMX texture references could not be resolved: {refs}",
                count=match.group(1),
                refs=match.group(2),
            )
        match = re.fullmatch(r"High vertex count: ([\d,]+) vertices; Source/GMod work may be slow\.", text)
        if match:
            return self._t("preflight.warning_high_vertex_count", "High vertex count: {count} vertices; Source/GMod work may be slow.", count=match.group(1))
        match = re.fullmatch(r"High morph/shapekey count: ([\d,]+); later flex work may be slow\.", text)
        if match:
            return self._t("preflight.warning_high_morph_count", "High morph/shapekey count: {count}; later flex work may be slow.", count=match.group(1))
        match = re.fullmatch(
            r"Potential NSFW shapekey names detected: ([\d,]+) keyword matches across ([\d,]+) morphs\. Auto porting is not optimized for this kind of model\.",
            text,
        )
        if match:
            return self._t(
                "preflight.warning_nsfw_summary",
                "Potential NSFW shapekey names detected: {match_count} keyword matches across {morph_count} morphs. Auto porting is not optimized for this kind of model.",
                match_count=match.group(1),
                morph_count=match.group(2),
            )
        match = re.fullmatch(r"High native PMX texture count: ([\d,]+); material work may be slow\.", text)
        if match:
            return self._t("preflight.warning_high_texture_count", "High native PMX texture count: {count}; material work may be slow.", count=match.group(1))
        return self.translate_runtime_text(text)

    def cancel_full_import(self) -> None:
        if self.worker and self.worker.isRunning() and hasattr(self.worker, "cancel"):
            self.worker.cancel()  # type: ignore[attr-defined]
            self.append_main_log("Cancel requested.")

    def full_import_done(self, result: dict) -> None:
        self.main_import_button.setEnabled(True)
        self.main_preflight_button.setEnabled(True)
        self.main_detect_gmod_button.setEnabled(True)
        self.main_cancel_button.setEnabled(False)
        output_folder = str(result.get("distribution_output_dir") or result.get("addon_dir") or result.get("gmod_addon_dir") or "")
        self.last_main_output_folder = output_folder
        self.main_open_output_button.setEnabled(bool(output_folder and Path(output_folder).exists()))
        self.main_output_files = result.get("qc_files") if isinstance(result.get("qc_files"), dict) else {}
        self.populate_main_files_table(self.main_output_files.get("files", []) if self.main_output_files else [])
        warnings = result.get("optional_warnings") if isinstance(result.get("optional_warnings"), list) else []
        if warnings:
            escaped = "<br>".join(html.escape(f"- {warning}") for warning in warnings)
            self.main_warnings_label.setText(f'<span style="color:#d29922;">Optional warnings:</span><br>{escaped}')
        else:
            self.main_warnings_label.setText('<span style="color:#2ea043;">All attempted steps completed without optional warnings.</span>')
        self.sync_main_results_to_step_tabs(result)
        self.refresh_workflow_statuses()
        self.refresh_workspace_cache_size()
        if output_folder and Path(output_folder).exists():
            QtGui.QDesktopServices.openUrl(QtCore.QUrl.fromLocalFile(output_folder))
        if warnings:
            preview = "\n".join(f"- {warning}" for warning in warnings[:8])
            if len(warnings) > 8:
                preview += f"\n- ... {len(warnings) - 8} more"
            QtWidgets.QMessageBox.warning(
                self,
                "Import complete with warnings",
                "The model was imported, compiled, and packaged, but some non-blocking issues were reported.\n\n" + preview,
            )
        else:
            QtWidgets.QMessageBox.information(self, "Import complete", "The model was imported, compiled, packaged, and copied to GMod addons.")

    def full_import_failed(self, message: str) -> None:
        self.main_import_button.setEnabled(True)
        self.main_preflight_button.setEnabled(True)
        self.main_detect_gmod_button.setEnabled(True)
        self.main_cancel_button.setEnabled(False)
        self.set_main_progress(self.main_progress_bar.value(), "Import Failed", "See the log for details.", "#f85149")
        failed_step, partial_steps = self.full_import_failure_context(message)
        if partial_steps:
            self.sync_main_results_to_step_tabs({"steps": partial_steps})
        if failed_step:
            self.prefill_failed_auto_step(failed_step, partial_steps)
            self.set_step_failed(failed_step, f"Auto import failed at Step {failed_step}")
        self.set_advanced_steps_visible(True)
        if failed_step:
            self.switch_to_step(failed_step)
        self.refresh_workspace_cache_size()
        self.show_error("Import to GMod failed", message)

    def full_import_failure_context(self, message: str) -> tuple[int, dict[object, object]]:
        failed_step = 0
        partial_steps: dict[object, object] = {}
        worker = self.worker
        raw_step = getattr(worker, "current_step", 0) if worker is not None else 0
        try:
            failed_step = int(raw_step or 0)
        except Exception:
            failed_step = 0
        raw_steps = getattr(worker, "step_results", {}) if worker is not None else {}
        if isinstance(raw_steps, dict):
            partial_steps = dict(raw_steps)
        if not failed_step:
            match = re.search(r"Step\s+(\d+)", message)
            if match:
                try:
                    failed_step = int(match.group(1))
                except Exception:
                    failed_step = 0
        return failed_step, partial_steps

    def full_import_step_input_from_results(self, step: int, steps: dict[object, object]) -> str:
        def step_data(number: int) -> dict[str, object]:
            value = steps.get(number) or steps.get(str(number))
            return value if isinstance(value, dict) else {}

        if step == 1:
            return self.main_source_row.value() if hasattr(self, "main_source_row") else ""
        previous_key_by_step = {
            2: (1, "blend"),
            3: (2, "blend"),
            4: (3, "blend"),
            5: (4, "blend"),
            6: (5, "blend"),
            7: (6, "blend"),
            8: (7, "blend"),
            9: (8, "blend"),
            10: (9, "final_dir"),
            11: (9, "final_dir"),
            12: (5, "materials_json"),
            13: (1, "workspace"),
            14: (9, "final_dir"),
            15: (14, "dir"),
        }
        lookup = previous_key_by_step.get(int(step))
        if not lookup:
            return ""
        source_step, key = lookup
        return str(step_data(source_step).get(key) or "")

    def refresh_step_preview_from_input(self, step: int) -> None:
        row_attr_by_step = {
            2: "fix_input_row",
            3: "spine_input_row",
            4: "sort_input_row",
            5: "material_input_row",
            6: "bodygroup_input_row",
            7: "flex_input_row",
            8: "collision_input_row",
            9: "proportion_input_row",
            10: "carms_input_row",
            11: "vrd_input_row",
            12: "texture_input_row",
            13: "icon_input_row",
            14: "qc_input_row",
            15: "release_input_row",
        }
        updater_by_step = {
            2: self.update_fix_output_preview,
            3: self.update_spine_output_preview,
            4: self.update_sort_output_preview,
            5: self.update_material_output_preview,
            6: self.update_bodygroup_output_preview,
            7: self.update_flex_output_preview,
            8: self.update_collision_output_preview,
            9: self.update_proportion_output_preview,
            10: self.update_carms_output_preview,
            11: self.update_vrd_output_preview,
            12: self.update_texture_output_preview,
            13: self.update_icon_output_preview,
            14: self.update_qc_output_preview,
            15: self.update_release_output_preview,
        }
        row = getattr(self, row_attr_by_step.get(int(step), ""), None)
        value = row.value().strip() if hasattr(row, "value") else ""
        updater = updater_by_step.get(int(step))
        if value and updater:
            updater(Path(value))
            self.fill_expected_step_paths(step, Path(value))

